const cfg = $('Workflow Configuration').first().json;
const maxSync = Number(cfg.maxSyncPerRun || 50);
const now = Date.now();
const lower = value => String(value || '').trim().toLowerCase();
const upper = value => String(value || '').trim().toUpperCase();
const isDue = value => !value || Date.parse(value) <= now;
const leaseExpired = row => !row.lease_until || Date.parse(row.lease_until) <= now;
const hasValidEmail = row => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(row.email || '').trim().toLowerCase());
const hasValidPhone = row => {
  const digits = String(row.phone_e164 || row.phone || '').replace(/\D/g, '');
  return (digits.length === 10) || (digits.length === 11 && digits.startsWith('1'));
};
const hasSyncIdentifier = row => hasValidEmail(row) || hasValidPhone(row);
const isQualified = row => {
  const qualificationStatus = lower(row.qualification_status);
  const legacyStatus = lower(row.status);
  const pipelineStatus = upper(row.pipeline_status);
  if (qualificationStatus === 'qualified' || legacyStatus === 'qualified') return true;
  return ['ENRICHED', 'DONE'].includes(pipelineStatus);
};
const isReadyForSync = row => {
  const syncStatus = lower(row.ghl_sync_status);
  if (syncStatus === 'failed') return isDue(row.next_retry_at);
  return true;
};
return $input.all()
  .map(item => item.json)
  .filter(row => isQualified(row))
  .filter(row => hasSyncIdentifier(row))
  .filter(row => !['synced', 'in_sync'].includes(lower(row.ghl_sync_status)))
  .filter(row => Number(row.attempt_count || 0) < Number(row.max_attempts || cfg.maxAttempts || 5))
  .filter(row => isReadyForSync(row) && leaseExpired(row))
  .slice(0, maxSync)
  .map(row => ({ json: row }));

const cfg = $('Workflow Configuration').first().json;
const now = new Date();
const norm = value => String(value || '').trim();
const slug = value => norm(value).toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '');
const normalizeEmail = value => {
  const email = norm(value).toLowerCase();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) ? email : '';
};
const normalizePhone = value => {
  const digits = String(value || '').replace(/\D/g, '');
  if (!digits) return '';
  if (digits.length === 11 && digits.startsWith('1')) return `+${digits}`;
  if (digits.length === 10) return `+1${digits}`;
  return '';
};
const customFields = [];
if (cfg.googleMapsFieldId) customFields.push({ id: cfg.googleMapsFieldId, value: norm($json.google_maps_url) });
if (cfg.matchedKeywordsFieldId) customFields.push({ id: cfg.matchedKeywordsFieldId, value: norm($json.matched_keywords) });
if (cfg.dedupeKeyFieldId) customFields.push({ id: cfg.dedupeKeyFieldId, value: norm($json.lead_id || $json.dedupe_key) });
const keywordTags = norm($json.matched_keywords).split(',').map(v => v.trim()).filter(Boolean).map(v => `kw_${slug(v)}`);
const tags = [...new Set(['source_google_maps', 'industry_med_spa', `city_${slug($json.city)}`, `state_${slug($json.state)}`, ...keywordTags])];
const email = normalizeEmail($json.email);
const number = normalizePhone($json.phone_e164 || $json.phone);
const payload = {
  locationId: cfg.ghlLocationId,
  firstName: norm($json.business_name).slice(0, 100),
  name: norm($json.business_name),
  companyName: norm($json.business_name),
  email: email || undefined,
  phone: number || undefined,
  website: norm($json.website) || undefined,
  address1: norm($json.full_address) || undefined,
  city: norm($json.city) || undefined,
  state: norm($json.state) || undefined,
  source: 'Google Maps Lead Gen',
  tags,
  customFields,
};
return {
  json: {
    ...$json,
    pipeline_status: 'SYNCING',
    status: 'SYNCING',
    stage: 'crm_sync',
    attempt_count: Number($json.attempt_count || 0) + 1,
    max_attempts: Number($json.max_attempts || cfg.maxAttempts || 5),
    lease_owner: `ghl-sync:${$execution.id || Date.now()}`,
    lease_until: new Date(now.getTime() + Number(cfg.leaseMinutes || 30) * 60 * 1000).toISOString(),
    updated_at: now.toISOString(),
    ghl_tags: tags.join(','),
    ghl_email: email,
    ghl_number: number,
    ghl_request: payload,
  }
};

const response = $json;
const previous = $input.item.json;
const contactId = response.contact?.id || response.id || '';
const syncedAt = new Date().toISOString();
const retryAt = attempt => new Date(Date.now() + Math.min(720, 15 * Math.pow(4, Math.max(0, attempt - 1))) * 60 * 1000).toISOString();
const attempts = Number(previous.attempt_count || 1);
const maxAttempts = Number(previous.max_attempts || 5);
const success = Boolean(contactId);
const leadId = previous.lead_id || previous.dedupe_key;
const dedupeKey = previous.dedupe_key || previous.lead_id;
return {
  json: {
    ...previous,
    lead_id: leadId,
    dedupe_key: dedupeKey,
    pipeline_status: success ? 'DONE' : (attempts >= maxAttempts ? 'FAILED_TERMINAL' : 'FAILED_RETRYABLE'),
    status: success ? 'DONE' : (attempts >= maxAttempts ? 'FAILED_TERMINAL' : 'FAILED_RETRYABLE'),
    stage: 'crm_sync',
    attempt_count: attempts,
    max_attempts: maxAttempts,
    next_retry_at: success ? '' : retryAt(attempts),
    lease_owner: '',
    lease_until: '',
    ghl_sync_status: success ? 'synced' : 'failed',
    ghl_contact_id: contactId,
    ghl_last_sync_at: syncedAt,
    ghl_error: success ? '' : JSON.stringify(response),
    done_at: success ? syncedAt : '',
    last_error_stage: success ? '' : 'crm_sync',
    last_error_code: success ? '' : String(response.statusCode || 'GHL_UPSERT_FAILED'),
    last_error: success ? '' : JSON.stringify(response).slice(0, 1000),
    schema_version: previous.schema_version || 'v1',
    sync_log: {
      log_id: `ghl-sync-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      lead_id: leadId,
      dedupe_key: dedupeKey,
      business_name: previous.business_name,
      ghl_contact_id: contactId,
      ghl_sync_status: success ? 'synced' : 'failed',
      request_tags: previous.ghl_tags || '',
      request_payload: JSON.stringify(previous.ghl_request),
      response_body: JSON.stringify(response),
      logged_at: syncedAt,
    },
  }
};

const now = new Date().toISOString();
return $input.all().map(item => ({
  json: {
    event_id: 'ghl-' + (item.json.lead_id || item.json.dedupe_key) + '-' + Date.now(),
    lead_id: item.json.lead_id || item.json.dedupe_key || '',
    search_job_id: '',
    workflow_name: 'med-spa-ghl-sync',
    execution_id: String($execution.id || ''),
    from_status: 'ENRICHED',
    to_status: item.json.pipeline_status || item.json.status || '',
    stage: 'crm_sync',
    message: item.json.ghl_sync_status === 'synced' ? 'Lead synced to GoHighLevel' : 'GoHighLevel sync failed',
    event_payload: JSON.stringify({ ghl_contact_id: item.json.ghl_contact_id, ghl_sync_status: item.json.ghl_sync_status }),
    created_at: now,
  }
}));

const now = new Date().toISOString();
return $input.all()
  .map(item => item.json)
  .filter(row => ['FAILED_RETRYABLE', 'FAILED_TERMINAL'].includes(String(row.pipeline_status || row.status || '').toUpperCase()))
  .map(row => ({
    json: {
      error_id: 'ghl-' + (row.lead_id || row.dedupe_key || Date.now()) + '-' + Date.now(),
      workflow_name: 'med-spa-ghl-sync',
      execution_id: String($execution.id || ''),
      record_type: 'lead',
      record_id: row.lead_id || row.dedupe_key || '',
      lead_id: row.lead_id || row.dedupe_key || '',
      search_job_id: '',
      stage: 'crm_sync',
      attempt_count: row.attempt_count || 0,
      error_code: row.last_error_code || 'GHL_UPSERT_FAILED',
      error_message: row.last_error || row.ghl_error || '',
      raw_error_json: JSON.stringify(row),
      retryable: String(row.pipeline_status || row.status || '').toUpperCase() === 'FAILED_RETRYABLE' ? 'true' : 'false',
      next_retry_at: row.next_retry_at || '',
      created_at: now,
    }
  }));
